class Solution {
public:
    double findMedianSortedArrays(vector<int>& nums1, vector<int>& nums2) {
        if (nums1.size() > nums2.size()) return findMedianSortedArrays(nums2, nums1);
        int m = nums1.size(), n = nums2.size();
        int lo = 0, hi = m;
        while (lo <= hi) {
            int i = lo + (hi - lo) / 2, j = (m + n + 1) / 2 - i;
            int maxLX = i ? nums1[i-1] : INT_MIN;
            int minRX = i < m ? nums1[i] : INT_MAX;
            int maxLY = j ? nums2[j-1] : INT_MIN;
            int minRY = j < n ? nums2[j] : INT_MAX;
            if (maxLX <= minRY && maxLY <= minRX) {
                if ((m+n)%2) return max(maxLX, maxLY);
                return (max(maxLX, maxLY) + min(minRX, minRY)) / 2.0;
            } else if (maxLX > minRY) hi = i - 1;
            else lo = i + 1;
        }
        return 0;
    }
};
